     2→import { AnimatePresence, motion } from 'framer-motion';
     3→import { useNavigate } from 'react-router-dom';
     4→
     5→const AuthModal = ({isOpen, onClose}) => {
     6→    const navigate = useNavigate();
     7→
     8→    const handleLogin = () => {
     9→        onClose();
    10→        navigate('/login');
    11→    }
    12→
    13→    const handleSignUp = () => {
    14→        onClose();
    15→        navigate('/signUp');
    16→    }
    17→
    18→    if(!isOpen) return null;
    19→
    20→    return(
    21→        <AnimatePresence>
    22→        <div className='auth-modal-overlay' onClick={onClose}>
    23→            <motion.div
    24→            className='auth-modal-container'
    25→            onClick={(e) => e.stopPropagation()}
    26→            initial={{opacity: 0, scale: 0.85}}
    27→            animate={{opacity: 1, scale: 1, transition: {type: 'spring', stiffness: 260, damping: 20}}}
    28→            exit={{opacity: 0, scale: 0.85, transition: {type: 'tween', duration: 0.15}}}
    29→            >
    30→                <button className='auth-modal-close' onClick={onClose}>
    31→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#333" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    32→                        <line x1="18" y1="6" x2="6" y2="18"/>
    33→                        <line x1="6" y1="6" x2="18" y2="18"/>
    34→                    </svg>
    35→                </button>
    36→
    37→                <div className='auth-modal-logo'>Iskrib</div>
    38→                <p className='auth-modal-message'>Sign in to interact with posts</p>
    39→
    40→                <div className='auth-modal-buttons'>
    41→                    <button onClick={handleLogin} className='auth-modal-login-bttn'>Log in</button>
    42→                    <button onClick={handleSignUp} className='auth-modal-signup-bttn'>Sign up</button>
    43→                </div>
    44→            </motion.div>
    45→        </div>
    46→        </AnimatePresence>
    47→    )
    48→}
    49→export default AuthModal;
    50→

